using System;
using UnityEngine;

namespace HeartopiaMod
{
    public partial class HeartopiaComplete
    {
        // Sidebar nav icons, rasterized offline via GDI+ (System.Drawing) from the original
        // artifact-mockup line-icon designs, then embedded as base64 PNG -- IMGUI has no path/
        // bezier renderer, so unlike the rest of this theme these are NOT generated at runtime.
        // White line art on transparent; tinted per-draw via GUI.color, same as every other
        // baked sprite in this file. Order matches DrawNavIcon's navIconIndex (0-8):
        // 0 Self, 1 Resource Gathering, 2 Features, 3 New Features, 4 Radar, 5 Teleport, 6 Bag/Warehouse, 7 Research, 8 Settings
        private static readonly string[] NavIconPngBase64 = new string[]
        {
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
        };

        private Texture2D[] navIconTextures;

        private Texture2D EnsureNavIconTexture(int index)
        {
            if (index < 0 || index >= NavIconPngBase64.Length)
            {
                return null;
            }

            if (this.navIconTextures == null)
            {
                this.navIconTextures = new Texture2D[NavIconPngBase64.Length];
            }

            if (this.navIconTextures[index] == null)
            {
                try
                {
                    byte[] bytes = Convert.FromBase64String(NavIconPngBase64[index]);
                    Texture2D tex = new Texture2D(2, 2, TextureFormat.RGBA32, false);
                    tex.hideFlags = HideFlags.DontUnloadUnusedAsset;
                    tex.wrapMode = TextureWrapMode.Clamp;
                    tex.filterMode = FilterMode.Bilinear;
                    if (!tex.LoadImage(bytes))
                    {
                        UnityEngine.Object.Destroy(tex);
                        return null;
                    }

                    this.navIconTextures[index] = tex;
                }
                catch
                {
                    // Fail-soft -- DrawNavIcon falls back to the primitive-composed icon.
                    return null;
                }
            }

            return this.navIconTextures[index];
        }
    }
}
